when.condition:
@{
                        var auth = context.Request.Headers.GetValueOrDefault("Authorization", "");
                        var token = auth.StartsWith("Bearer ") ? auth.Substring(7) : auth;
                        var jwt = token.AsJwt();
                        var oid = jwt?.Claims.GetValueOrDefault("oid") ?? "";
                        return oid != "f24cc6b6-f729-4363-8ed5-42475e5d7269";
                    }

@{
                        string clientSig = context.Request.Headers.GetValueOrDefault("X-Fido-Signature", "");
                        byte[] secret = System.Text.Encoding.UTF8.GetBytes("JUICE_SHOP_SECURE_KEY_2024");
                        byte[] pathBytes = System.Text.Encoding.UTF8.GetBytes(context.Request.Url.Path);
                        var hmac = new System.Security.Cryptography.HMACSHA256(secret);
                        byte[] hash = hmac.ComputeHash(pathBytes);
                        string expectedSig = System.Convert.ToBase64String(hash);
                        return clientSig != expectedSig;
                    }
